package com.example.yourappname // Replace with your actual package name

import android.content.Context
import android.content.SharedPreferences

// Data class to hold user session information
data class UserSession(val token: String, val userId: String)

class AuthManager(context: Context) {

    private val sharedPreferences: SharedPreferences
    private val editor: SharedPreferences.Editor

    // SharedPreferences file name
    companion object {
        private const val PREFS_FILE_NAME = "MyAppAuthPrefs"
        private const val KEY_AUTH_TOKEN = "authToken"
        private const val KEY_USER_ID = "userId"
    }

    init {
        sharedPreferences = context.getSharedPreferences(PREFS_FILE_NAME, Context.MODE_PRIVATE)
        editor = sharedPreferences.edit()
    }

    /**
     * Saves the user's authentication token and ID.
     * Call this method after a successful login or registration.
     */
    fun saveUserSession(token: String, userId: String) {
        editor.putString(KEY_AUTH_TOKEN, token)
        editor.putString(KEY_USER_ID, userId)
        editor.apply() // Apply changes asynchronously
    }

    /**
     * Retrieves the current user's session information.
     * Returns null if no user is logged in.
     */
    fun getCurrentUserSession(): UserSession? {
        val token = sharedPreferences.getString(KEY_AUTH_TOKEN, null)
        val userId = sharedPreferences.getString(KEY_USER_ID, null)

        return if (token != null && userId != null) {
            UserSession(token, userId)
        } else {
            null
        }
    }

    /**
     * Checks if a user is currently logged in.
     */
    fun isLoggedIn(): Boolean {
        return getCurrentUserSession() != null
    }

    /**
     * Clears the user's session information, effectively logging them out.
     */
    fun clearUserSession() {
        editor.remove(KEY_AUTH_TOKEN)
        editor.remove(KEY_USER_ID)
        editor.apply() // Apply changes asynchronously
    }
}